export const DEFAULT_PROGRESS_MIN = 0;
export const DEFAULT_PROGRESS_MAX = 100;
export const DEFAULT_PROGRESS_VALUE = 0;

// Size variants
export const ProgressSizes = ["sm", "lg"] as const;
export type ProgressSize = (typeof ProgressSizes)[number];
export const DEFAULT_PROGRESS_SIZE: ProgressSize = "sm";

// Visual variants
export const ProgressVariants = ["solid", "outline"] as const;
export type ProgressVariant = (typeof ProgressVariants)[number];
export const DEFAULT_PROGRESS_VARIANT: ProgressVariant = "solid";

// Radius variants
export const ProgressRadiuses = ["none", "sm"] as const;
export type ProgressRadius = (typeof ProgressRadiuses)[number];
export const DEFAULT_PROGRESS_RADIUS: ProgressRadius = "none";
