import { forwardRef } from "react";
import { ProgressBar as AriaProgressBar } from "react-aria-components";
import { clsx } from "clsx";
import * as styles from "./Progress.css";
import {
  DEFAULT_PROGRESS_MAX,
  DEFAULT_PROGRESS_MIN,
  DEFAULT_PROGRESS_RADIUS,
  DEFAULT_PROGRESS_SIZE,
  DEFAULT_PROGRESS_VALUE,
  DEFAULT_PROGRESS_VARIANT,
  type ProgressRadius,
  type ProgressSize,
  type ProgressVariant,
} from "./Progress.config";

interface ProgressCustomProps {
  /**
   * The smallest value allowed for the progress bar.
   * @default 0
   */
  min?: number;

  /**
   * The largest value allowed for the progress bar.
   * @default 100
   */
  max?: number;

  /**
   * The current value (controlled).
   * @default 0
   */
  value?: number;

  /**
   * A string value that labels the progress bar for assistive technologies.
   * This is set as the `aria-label` attribute on the progressbar element.
   * @example "Completion progress of your job post"
   */
  label?: string;

  /**
   * Human-readable text representing the current value, announced by screen readers
   * via a live region. Use this to provide a more descriptive value than the percentage.
   * @example "5 steps out of 10"
   */
  valueText?: string;

  /**
   * The size of the progress bar.
   * @default 'sm'
   */
  size?: ProgressSize;

  /**
   * The visual variant of the progress bar.
   * @default 'solid'
   */
  variant?: ProgressVariant;

  /**
   * The border radius of the progress bar.
   * @default 'none'
   */
  radius?: ProgressRadius;

  /**
   * Whether to animate the progress bar fill when the value changes.
   * @default false
   */
  animation?: boolean;
}

export interface ProgressProps
  extends
    Omit<React.HTMLAttributes<HTMLDivElement>, keyof ProgressCustomProps>,
    ProgressCustomProps {}

export const Progress = forwardRef<HTMLDivElement, ProgressProps>(
  (
    {
      min = DEFAULT_PROGRESS_MIN,
      max = DEFAULT_PROGRESS_MAX,
      value = DEFAULT_PROGRESS_VALUE,
      label,
      valueText,
      size = DEFAULT_PROGRESS_SIZE,
      variant = DEFAULT_PROGRESS_VARIANT,
      radius = DEFAULT_PROGRESS_RADIUS,
      animation = false,
      className,
      ...props
    },
    ref
  ) => {
    // Filter out undefined values to satisfy exactOptionalPropertyTypes
    const filteredProps = Object.fromEntries(
      Object.entries(props).filter(([, v]) => v !== undefined)
    );

    return (
      <AriaProgressBar
        ref={ref}
        value={value}
        minValue={min}
        maxValue={max}
        {...(label && { "aria-label": label })}
        className={clsx(styles.root, className)}
        {...filteredProps}
      >
        {({ percentage }) => (
          <>
            {/* Visually hidden value text for screen readers */}
            {valueText && (
              <span aria-live="polite" className={styles.valueText}>
                {valueText}
              </span>
            )}

            {/* Track and fill */}
            <div className={styles.track({ size, variant, radius })}>
              <div
                className={styles.fill({ radius, animation })}
                style={{ width: `${percentage}%` }}
              />
            </div>
          </>
        )}
      </AriaProgressBar>
    );
  }
);

Progress.displayName = "Progress";
